        let mw = BodyLimitMiddleware::with_limit(1024).unwrap();
        let (mut parts, _) = http::Request::builder()
            .uri("/upload")
            .header("Content-Length", "2048")
            .body(())
            .unwrap()
            .into_parts();
        let ctx = make_ctx();
        let result = mw.handle_request(&mut parts, &ctx).await.unwrap();
        assert!(result.is_some());
