        router.set_traffic("v1", 60, "unknown-revision", 40);

        let v1 = router.get_revision("v1").unwrap();
        let v2 = router.get_revision("v2").unwrap();
        assert_eq!(v1.traffic_percent(), 60);
        assert_eq!(v2.traffic_percent(), 20); // unchanged
