        let mgr = default_manager();
        let cookie = mgr.build_cookie("abc-123");
        assert!(cookie.contains("gateway_sticky=abc-123"));
        assert!(cookie.contains("Path=/"));
        assert!(cookie.contains("HttpOnly"));
